import boto3

s3 = boto3.client("s3")

def apply_legal_hold(bucket: str, prefix: str, hold_id: str) -> None:
    """
    Tag all objects under prefix with a legal hold label so that
    S3 lifecycle rules (configured with a tag filter) skip deletion.
    This is separate from S3 Object Lock; it relies on a conditional
    lifecycle rule: Expiration only fires when legal-hold tag is absent.
    """
    paginator = s3.get_paginator("list_objects_v2")
    count = 0
    for page in paginator.paginate(Bucket=bucket, Prefix=prefix):
        for obj in page.get("Contents", []):
            s3.put_object_tagging(
                Bucket=bucket,
                Key=obj["Key"],
                Tagging={"TagSet": [{"Key": "legal-hold", "Value": hold_id}]},
            )
            count += 1
    audit_log.record({"event": "legal_hold_applied", "hold_id": hold_id,
                      "prefix": prefix, "object_count": count})

def release_legal_hold(bucket: str, prefix: str, hold_id: str) -> None:
    """Remove hold tags — normal lifecycle deletion resumes for these objects."""
    paginator = s3.get_paginator("list_objects_v2")
    for page in paginator.paginate(Bucket=bucket, Prefix=prefix):
        for obj in page.get("Contents", []):
            existing = s3.get_object_tagging(Bucket=bucket, Key=obj["Key"])
            tags = [
                t for t in existing["TagSet"]
                if not (t["Key"] == "legal-hold" and t["Value"] == hold_id)
            ]
            s3.put_object_tagging(
                Bucket=bucket, Key=obj["Key"],
                Tagging={"TagSet": tags}
            )
    audit_log.record({"event": "legal_hold_released", "hold_id": hold_id})
